import math

def is_prime(n):
    if n == 1 or n <= 0 or n % 1 > 0:
        return False
    sqrt_n = int(math.sqrt(n))
    for i in range(2, sqrt_n + 1):
        if n % i == 0:
            return False
    return True

def is_fibonacci(n):
    if n < 0 or n % 1 > 0:
        return False
    x = 5 * n**2
    return math.isqrt(x + 4)**2 == (x + 4) or math.isqrt(x - 4)**2 == (x - 4)

